mapper.select:
SELECT * FROM biomed_sample

     AND id = #{id}
     AND sample_no LIKE CONCAT('%', #{sampleNo}, '%')
     AND sample_type_id = #{sampleTypeId}
     AND queue LIKE CONCAT('%', #{queue}, '%')
     AND source LIKE CONCAT('%', #{source}, '%')
     AND sample_name LIKE CONCAT('%', #{sampleName}, '%')
     AND storage_id = #{storageId}
     AND status = #{status}
     AND create_by = #{createBy}

ORDER BY id DESC

