UPDATE biomed_sample
sample_no = #{sampleNo}, sample_type_id = #{sampleTypeId}, queue = #{queue}, collect_time = #{collectTime}, source = #{source}, storage_id = #{storageId}, sample_name = #{sampleName}, status = #{status}, update_time = NOW()
