mapper.select:
SELECT queue AS queue, COUNT(id) AS count
FROM biomed_sample

    queue IS NOT NULL AND queue != ''
     AND create_by = #{createBy}
     AND queue = #{queueName}
     AND sample_type_id = #{sampleTypeId}
     AND collect_time >= #{startDate}
     AND collect_time <= #{endDate}

GROUP BY queue
ORDER BY count DESC

SELECT DATE(collect_time) AS collectDate, COUNT(id) AS count
FROM biomed_sample

    collect_time IS NOT NULL
     AND create_by = #{createBy}
     AND queue = #{queueName}
     AND sample_type_id = #{sampleTypeId}
     AND collect_time >= #{start}
     AND collect_time <= #{end}

GROUP BY DATE(collect_time)
ORDER BY collectDate ASC

SELECT st.id AS typeId, st.type_name AS typeName, COUNT(bs.id) AS count
FROM sample_type st
LEFT JOIN biomed_sample bs ON st.id = bs.sample_type_id
 AND bs.create_by = #{createBy}
 AND bs.queue = #{queueName}
 AND bs.sample_type_id = #{sampleTypeId}
 AND bs.collect_time >= #{startDate}
 AND bs.collect_time <= #{endDate}
GROUP BY st.id, st.type_name
ORDER BY count DESC

SELECT * FROM biomed_sample
AND sample_name LIKE CONCAT('%', #{sampleName}, '%') AND sample_no LIKE CONCAT('%', #{sampleNo}, '%') AND sample_type_id = #{sampleTypeId} AND queue LIKE CONCAT('%', #{queue}, '%') AND create_by = #{createBy}
ORDER BY id DESC
